return-response.set-body:
@{
            return new JObject(
                new JProperty("tournament", "FIFA World Cup 2026"),
                new JProperty("hostCountries", new JArray("United States", "Canada", "Mexico")),
                new JProperty("groups", new JArray(
                    new JObject(
                        new JProperty("group", "A"),
                        new JProperty("teams", new JArray("United States", "Germany", "Japan", "Mexico"))
                    ),
                    new JObject(
                        new JProperty("group", "B"),
                        new JProperty("teams", new JArray("Brazil", "France", "England", "South Korea"))
                    )
                )),
                new JProperty("responseType", "Mocked APIM response"),
                new JProperty("authentication", "AWS SSO federated through Microsoft Entra ID"),
                new JProperty("governance", "Per-user and per-group APIM token governance enabled")
            ).ToString();
        }
